import math
from itertools import permutations

class Solution:
    def isDigitorialPermutation(self, n: int) -> bool:
        # Independent approach: literally enumerate every distinct permutation of
        # n's digits that doesn't start with zero, and test each as a number.
        fact = [math.factorial(i) for i in range(10)]
        digits = list(str(n))
        seen = set()
        for p in permutations(digits):
            if p[0] == '0':
                continue
            candidate = ''.join(p)
            if candidate in seen:
                continue
            seen.add(candidate)
            total = sum(fact[int(d)] for d in p)
            if total == int(candidate):
                return True
        return False

