class Solution:
    def isDigitorialPermutation(self, n: int) -> bool:
        fact = [1, 1, 2, 6, 24, 120, 720, 5040, 40320, 362880]
        digits = [int(c) for c in str(n)]
        total = sum(fact[d] for d in digits)
        return sorted(digits) == sorted(int(c) for c in str(total))

